if ( ! defined( 'ABSPATH' ) ) { exit; } class TCT_Economy_Normalizer { const META_SNAPSHOTS = 'tct_economy_snapshots'; const CRON_HOOK_NIGHTLY = 'tct_economy_snapshot_nightly'; const RETENTION_DAYS = 65; private static $yearly_max_cache = array(); private static $snapshots_cache = array(); public static function compute_yearly_max_points( $user_id ) { $user_id = (int) $user_id; if ( $user_id <= 0 ) { return 0; } if ( isset( self::$yearly_max_cache[ $user_id ] ) ) { return (int) self::$yearly_max_cache[ $user_id ]; } if ( ! class_exists( 'TCT_Reward' ) || ! method_exists( 'TCT_Reward', 'compute_monthly_max_points' ) ) { return 0; } $tz = TCT_Utils::wp_timezone(); try { $now = new DateTimeImmutable( 'now', $tz ); } catch ( Exception $e ) { return 0; } $total = 0; for ( $i = 0; $i < 12; $i++ ) { try { if ( 0 === $i ) { $month_start = $now->modify( 'first day of this month' )->setTime( 0, 0, 0 ); } else { $month_start = $now->modify( 'first day of this month' ) ->setTime( 0, 0, 0 ) ->modify( '+' . $i . ' months' ); } $month_end = $month_start->modify( 'first day of next month' )->setTime( 0, 0, 0 ); } catch ( Exception $e ) { continue; } $monthly = (int) TCT_Reward::compute_monthly_max_points( $user_id, $month_start, $month_end ); $total += $monthly; if ( $total > 2147483647 ) { $total = 2147483647; break; } } self::$yearly_max_cache[ $user_id ] = (int) $total; return (int) $total; } public static function invalidate_cache( $user_id ) { $user_id = (int) $user_id; unset( self::$yearly_max_cache[ $user_id ] ); } public static function record_snapshot( $user_id, $date_key = '', $yearly_max = 0 ) { $user_id = (int) $user_id; if ( $user_id <= 0 ) { return; } if ( '' === $date_key ) { try { $tz = TCT_Utils::wp_timezone(); $now = new DateTimeImmutable( 'now', $tz ); $date_key = $now->format( 'Y-m-d' ); } catch ( Exception $e ) { $date_key = gmdate( 'Y-m-d' ); } } $yearly_max = (int) $yearly_max; if ( $yearly_max <= 0 ) { self::invalidate_cache( $user_id ); $yearly_max = self::compute_yearly_max_points( $user_id ); } if ( $yearly_max <= 0 ) { return; } $snapshots = self::get_snapshots( $user_id ); $snapshots[ $date_key ] = array( 'yearly_max' => $yearly_max ); self::save_snapshots( $user_id, $snapshots ); } public static function record_snapshot_on_economy_change( $user_id ) { self::invalidate_cache( $user_id ); self::record_snapshot( $user_id ); } public static function get_snapshots( $user_id ) { $user_id = (int) $user_id; if ( $user_id <= 0 ) { return array(); } if ( isset( self::$snapshots_cache[ $user_id ] ) && is_array( self::$snapshots_cache[ $user_id ] ) ) { return self::$snapshots_cache[ $user_id ]; } $raw = get_user_meta( $user_id, self::META_SNAPSHOTS, true ); if ( ! is_string( $raw ) || '' === trim( $raw ) ) { self::$snapshots_cache[ $user_id ] = array(); return array(); } $decoded = json_decode( $raw, true ); if ( ! is_array( $decoded ) ) { self::$snapshots_cache[ $user_id ] = array(); return array(); } self::$snapshots_cache[ $user_id ] = $decoded; return $decoded; } private static function save_snapshots( $user_id, $snapshots ) { $user_id = (int) $user_id; if ( $user_id <= 0 || ! is_array( $snapshots ) ) { return; } $cutoff = ''; try { $tz = TCT_Utils::wp_timezone(); $now = new DateTimeImmutable( 'now', $tz ); $cutoff = $now->modify( '-' . self::RETENTION_DAYS . ' days' )->format( 'Y-m-d' ); } catch ( Exception $e ) { } if ( '' !== $cutoff ) { foreach ( array_keys( $snapshots ) as $dk ) { if ( ! is_string( $dk ) ) { unset( $snapshots[ $dk ] ); continue; } if ( strcmp( $dk, $cutoff ) < 0 ) { unset( $snapshots[ $dk ] ); } } } update_user_meta( $user_id, self::META_SNAPSHOTS, wp_json_encode( $snapshots ) ); self::$snapshots_cache[ $user_id ] = $snapshots; } public static function get_snapshot_yearly_max( $user_id, $date_key ) { $snapshots = self::get_snapshots( $user_id ); if ( isset( $snapshots[ $date_key ] ) && is_array( $snapshots[ $date_key ] ) ) { return isset( $snapshots[ $date_key ]['yearly_max'] ) ? (int) $snapshots[ $date_key ]['yearly_max'] : 0; } return 0; } public static function run_nightly_snapshot() { $user_ids = self::get_users_with_points(); if ( empty( $user_ids ) ) { return; } foreach ( $user_ids as $uid ) { $uid = (int) $uid; if ( $uid <= 0 ) { continue; } self::invalidate_cache( $uid ); self::record_snapshot( $uid ); } } private static function get_users_with_points() { global $wpdb; $meta_key = TCT_Ledger::META_POINTS_STARTED_AT; $ids = $wpdb->get_col( $wpdb->prepare( "SELECT DISTINCT user_id FROM {$wpdb->usermeta} WHERE meta_key = %s", $meta_key ) ); return is_array( $ids ) ? array_map( 'intval', $ids ) : array(); } public static function schedule_nightly() { if ( wp_next_scheduled( self::CRON_HOOK_NIGHTLY ) ) { return; } try { $tz = TCT_Utils::wp_timezone(); $now = new DateTimeImmutable( 'now', $tz ); $target = $now->setTime( 23, 55, 0 ); if ( $target->getTimestamp() <= $now->getTimestamp() ) { $target = $target->modify( '+1 day' ); } $ts = $target->getTimestamp(); } catch ( Exception $e ) { $ts = time() + 86400; } wp_schedule_event( $ts, 'daily', self::CRON_HOOK_NIGHTLY ); } public static function unschedule_nightly() { $timestamp = wp_next_scheduled( self::CRON_HOOK_NIGHTLY ); while ( $timestamp ) { wp_unschedule_event( $timestamp, self::CRON_HOOK_NIGHTLY ); $timestamp = wp_next_scheduled( self::CRON_HOOK_NIGHTLY ); } } public static function get_normalized_earned_lost( $user_id, $start_utc_mysql, $end_utc_mysql ) { $user_id = (int) $user_id; if ( $user_id <= 0 ) { return array( 'earned' => 0, 'lost' => 0 ); } $snapshots = self::get_snapshots( $user_id ); if ( empty( $snapshots ) ) { return TCT_Ledger::get_earned_lost_in_range( $user_id, $start_utc_mysql, $end_utc_mysql ); } $today_key = ''; $tz = null; try { $tz = TCT_Utils::wp_timezone(); $today_key = ( new DateTimeImmutable( 'now', $tz ) )->format( 'Y-m-d' ); } catch ( Exception $e ) { $tz = new DateTimeZone( 'UTC' ); $today_key = gmdate( 'Y-m-d' ); } $start_key = ''; $end_key = ''; try { $utc = new DateTimeZone( 'UTC' ); $start_obj = new DateTimeImmutable( (string) $start_utc_mysql, $utc ); $end_obj = new DateTimeImmutable( (string) $end_utc_mysql, $utc ); if ( $tz instanceof DateTimeZone ) { $start_key = $start_obj->setTimezone( $tz )->format( 'Y-m-d' ); $end_key = $end_obj->setTimezone( $tz )->format( 'Y-m-d' ); } } catch ( Exception $e ) { } if ( '' !== $start_key && $start_key === $today_key && $end_key === $today_key ) { return TCT_Ledger::get_earned_lost_in_range( $user_id, $start_utc_mysql, $end_utc_mysql ); } if ( '' !== $start_key && '' !== $end_key && strcmp( $start_key, $end_key ) <= 0 ) { $has_snapshot_in_range = false; foreach ( $snapshots as $dk => $meta ) { if ( ! is_string( $dk ) || '' === $dk ) { continue; } if ( $dk === $today_key ) { continue; } if ( strcmp( $dk, $start_key ) < 0 || strcmp( $dk, $end_key ) > 0 ) { continue; } $ym = ( is_array( $meta ) && isset( $meta['yearly_max'] ) ) ? (int) $meta['yearly_max'] : 0; if ( $ym > 0 ) { $has_snapshot_in_range = true; break; } } if ( ! $has_snapshot_in_range ) { return TCT_Ledger::get_earned_lost_in_range( $user_id, $start_utc_mysql, $end_utc_mysql ); } } $today_max = 0; if ( isset( $snapshots[ $today_key ] ) && is_array( $snapshots[ $today_key ] ) ) { $today_max = isset( $snapshots[ $today_key ]['yearly_max'] ) ? (int) $snapshots[ $today_key ]['yearly_max'] : 0; } if ( $today_max <= 0 ) { $today_max = self::compute_yearly_max_points( $user_id ); if ( $today_max <= 0 ) { return TCT_Ledger::get_earned_lost_in_range( $user_id, $start_utc_mysql, $end_utc_mysql ); } self::record_snapshot( $user_id, $today_key, $today_max ); $snapshots[ $today_key ] = array( 'yearly_max' => (int) $today_max ); self::$snapshots_cache[ $user_id ] = $snapshots; } self::$yearly_max_cache[ $user_id ] = (int) $today_max; if ( '' !== $start_key && $start_key === $end_key && $start_key !== $today_key ) { $snapshot_max = 0; if ( isset( $snapshots[ $start_key ] ) && is_array( $snapshots[ $start_key ] ) ) { $snapshot_max = isset( $snapshots[ $start_key ]['yearly_max'] ) ? (int) $snapshots[ $start_key ]['yearly_max'] : 0; } $raw = TCT_Ledger::get_earned_lost_in_range( $user_id, $start_utc_mysql, $end_utc_mysql ); if ( $snapshot_max > 0 ) { $ratio = (float) $today_max / (float) $snapshot_max; return array( 'earned' => (int) round( (float) $raw['earned'] * $ratio ), 'lost' => (int) round( (float) $raw['lost'] * $ratio ), ); } return $raw; } $daily = TCT_Ledger::get_earned_lost_by_day( $user_id, $start_utc_mysql, $end_utc_mysql ); if ( empty( $daily ) ) { return array( 'earned' => 0, 'lost' => 0 ); } $total_earned = 0.0; $total_lost = 0.0; foreach ( $daily as $row ) { $day_key = isset( $row['day_local'] ) ? (string) $row['day_local'] : ''; $day_earned = isset( $row['earned'] ) ? (int) $row['earned'] : 0; $day_lost = isset( $row['lost'] ) ? (int) $row['lost'] : 0; if ( '' === $day_key ) { $total_earned += (float) $day_earned; $total_lost += (float) $day_lost; continue; } if ( $day_key === $today_key ) { $total_earned += (float) $day_earned; $total_lost += (float) $day_lost; continue; } $snapshot_max = 0; if ( isset( $snapshots[ $day_key ] ) && is_array( $snapshots[ $day_key ] ) ) { $snapshot_max = isset( $snapshots[ $day_key ]['yearly_max'] ) ? (int) $snapshots[ $day_key ]['yearly_max'] : 0; } if ( $snapshot_max <= 0 ) { $total_earned += (float) $day_earned; $total_lost += (float) $day_lost; continue; } $ratio = (float) $today_max / (float) $snapshot_max; $total_earned += (float) $day_earned * $ratio; $total_lost += (float) $day_lost * $ratio; } return array( 'earned' => (int) round( $total_earned ), 'lost' => (int) round( $total_lost ), ); } } 
